private boolean validateJWTToken(String token) {
    if (redisTokenService.isTokenBlacklisted(token)) {
        return false;
    }
    Jwts.parserBuilder()
            .setSigningKey(getSigningKey())
            .build()
            .parseClaimsJws(token);
    return true;
}

